diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
index fdef49e310f8..15bc9478df83 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
@@ -850,13 +850,31 @@ Instruction *InstCombinerImpl::visitTrunc(TruncInst &Trunc) {
       }
     }

+    // trunc (lshr Pow2, X) to i1 --> icmp eq X, log2(Pow2)
+    // When shifting a power-of-two right by X, the result has bit 0 set
+    // only when X equals the position of that bit (log2(Pow2)).
+    if (match(Src, m_LShr(m_Power2(C1), m_Value(X)))) {
+      Constant *Log2C1 = ConstantInt::get(SrcTy, C1->exactLogBase2());
+      return new ICmpInst(ICmpInst::ICMP_EQ, X, Log2C1);
+    }
+
+    // trunc (lshr (Pow2 - 1), X) to i1 --> icmp ult X, log2(Pow2)
+    // When shifting (2^n - 1) right by X, the result has bit 0 set
+    // for all X < n. This is equivalent to icmp ult X, n.
+    const APInt *CVal;
+    if (match(Src, m_LShr(m_APInt(CVal), m_Value(X)))) {
+      APInt PlusOne = *CVal + 1;
+      if (PlusOne.isPowerOf2()) {
+        Constant *Log2 = ConstantInt::get(SrcTy, PlusOne.logBase2());
+        return new ICmpInst(ICmpInst::ICMP_ULT, X, Log2);
+      }
+    }
     if (Trunc.hasNoUnsignedWrap() || Trunc.hasNoSignedWrap()) {
       Value *X, *Y;
       if (match(Src, m_Xor(m_Value(X), m_Value(Y))))
         return new ICmpInst(ICmpInst::ICMP_NE, X, Y);
     }
   }
-
   Value *A, *B;
   Constant *C;
   if (match(Src, m_LShr(m_SExt(m_Value(A)), m_Constant(C)))) {
@@ -895,7 +913,6 @@ Instruction *InstCombinerImpl::visitTrunc(TruncInst &Trunc) {
     }
     // TODO: Mask high bits with 'and'.
   }
-
   if (Instruction *I = narrowBinOp(Trunc))
     return I;

log.body:
define i1 @fold_ashr_power_of_2_minus_1(i8 %x) {
; CHECK-LABEL: define i1 @fold_ashr_power_of_2_minus_1(
; CHECK-SAME: i8 [[X:%.*]]) {
; CHECK-NEXT:    [[TRUNC:%.*]] = icmp ult i8 [[X]], 4
; CHECK-NEXT:    ret i1 [[TRUNC]]
  %ashr = ashr i8 15, %x
  %trunc = trunc i8 %ashr to i1
  ret i1 %trunc
}

